import fs from "node:fs";
import path from "node:path";

const INPUT_FILES = {
  schedules: "schedules.json",
  scheduleMonths: "schedule-months.json",
  discography: "discography.json",
};

export const SCHEMA_DRAFT_SQL = `-- Supabase schema draft (Phase 3-E)
-- Generated by static-to-astro — DO NOT apply to production without review.
-- No RLS, Auth, or Storage policies in this draft.

-- Suggested insert order: schedule_months → schedules → discography → discography_tracks

-- ---------------------------------------------------------------------------
-- schedule_months
-- ---------------------------------------------------------------------------
create table if not exists schedule_months (
  id uuid primary key default gen_random_uuid(),
  month text unique not null,
  label text not null,
  route text not null,
  count integer default 0,
  sort_order integer default 0,
  published boolean default true,
  created_at timestamptz default now(),
  updated_at timestamptz default now()
);

-- ---------------------------------------------------------------------------
-- schedules
-- ---------------------------------------------------------------------------
create table if not exists schedules (
  id uuid primary key default gen_random_uuid(),
  legacy_id text unique,
  date date not null,
  year integer,
  month text,
  title text,
  venue text,
  open_time text,
  start_time text,
  price text,
  description text,
  image_url text,
  home_image_url text,
  source_file text,
  source_route text,
  show_on_home boolean default false,
  home_order integer,
  published boolean default true,
  sort_order integer default 0,
  created_at timestamptz default now(),
  updated_at timestamptz default now()
);

create index if not exists schedules_date_idx on schedules (date);
create index if not exists schedules_month_idx on schedules (month);
create index if not exists schedules_show_on_home_idx on schedules (show_on_home) where show_on_home = true;

-- ---------------------------------------------------------------------------
-- discography
-- ---------------------------------------------------------------------------
create table if not exists discography (
  id uuid primary key default gen_random_uuid(),
  legacy_id text unique,
  title text not null,
  artist text,
  release_date date,
  year integer,
  label text,
  catalog_number text,
  description text,
  cover_image_url text,
  purchase_url text,
  streaming_url text,
  sort_order integer default 0,
  published boolean default true,
  source_file text,
  source_route text,
  created_at timestamptz default now(),
  updated_at timestamptz default now()
);

-- ---------------------------------------------------------------------------
-- discography_tracks
-- ---------------------------------------------------------------------------
create table if not exists discography_tracks (
  id uuid primary key default gen_random_uuid(),
  discography_legacy_id text not null,
  track_number integer not null,
  title text not null,
  sort_order integer default 0,
  created_at timestamptz default now()
  -- FK proposal (enable after discography rows exist):
  -- , foreign key (discography_legacy_id) references discography(legacy_id) on delete cascade
);

create index if not exists discography_tracks_legacy_id_idx on discography_tracks (discography_legacy_id);

-- ---------------------------------------------------------------------------
-- Optional: updated_at trigger (not included — add in Phase 3-F)
-- RLS: enable row level security + policies in Phase 3-F
-- Storage: bucket for schedule flyers + discography covers
-- ---------------------------------------------------------------------------
`;

/**
 * @param {string} dataDir
 */
export function loadSeedInputs(dataDir) {
  const dataAbs = path.resolve(dataDir);
  const loaded = {};

  for (const [key, fileName] of Object.entries(INPUT_FILES)) {
    const filePath = path.join(dataAbs, fileName);
    if (!fs.existsSync(filePath)) {
      loaded[key] = { path: filePath, present: false, data: null };
      continue;
    }
    const raw = fs.readFileSync(filePath, "utf8");
    loaded[key] = {
      path: filePath,
      present: true,
      data: JSON.parse(raw),
    };
  }

  return { dataDir: dataAbs, loaded };
}

/**
 * @param {Array<object>} schedules
 */
export function transformSchedulesForSupabase(schedules) {
  return schedules.map((row, index) => ({
    legacy_id: row.id,
    date: row.date ?? null,
    year: row.year ?? null,
    month: row.month ?? null,
    title: row.title ?? null,
    venue: row.venue ?? null,
    open_time: row.open_time ?? null,
    start_time: row.start_time ?? null,
    price: row.price ?? null,
    description: row.description ?? null,
    image_url: row.image ?? null,
    home_image_url: row.home_image ?? null,
    source_file: row.source_file ?? null,
    source_route: row.source_route ?? null,
    show_on_home: Boolean(row.show_on_home),
    home_order: row.home_order ?? null,
    published: row.published !== false,
    sort_order: index + 1,
  }));
}

/**
 * @param {Array<object>} months
 */
export function transformScheduleMonthsForSupabase(months) {
  return months.map((row, index) => ({
    month: row.month,
    label: row.label,
    route: row.route,
    count: row.count ?? 0,
    sort_order: index + 1,
    published: true,
  }));
}

/**
 * @param {Array<object>} releases
 */
export function transformDiscographyForSupabase(releases) {
  return releases.map((row) => ({
    legacy_id: row.id,
    title: row.title ?? row.heading ?? "Untitled",
    artist: row.artist ?? null,
    release_date: row.release_date ?? null,
    year: row.year ?? null,
    label: row.label ?? null,
    catalog_number: row.catalog_number ?? null,
    description: row.description ?? null,
    cover_image_url: row.cover_image ?? null,
    purchase_url: row.purchase_url ?? null,
    streaming_url: row.streaming_url ?? null,
    sort_order: row.sort_order ?? null,
    published: row.published !== false,
    source_file: row.source_file ?? null,
    source_route: row.source_route ?? null,
  }));
}

/**
 * @param {Array<object>} releases
 */
export function transformDiscographyTracksForSupabase(releases) {
  const tracks = [];
  for (const release of releases) {
    const legacyId = release.id;
    for (const t of release.tracks ?? []) {
      tracks.push({
        discography_legacy_id: legacyId,
        track_number: t.number ?? null,
        title: t.title,
        sort_order: t.number ?? null,
      });
    }
  }
  return tracks;
}

function countNulls(rows, fields) {
  const counts = {};
  for (const field of fields) {
    counts[field] = rows.filter((r) => r[field] == null || r[field] === "").length;
  }
  return counts;
}

function collectImageUrls(schedules, discography) {
  const urls = [];
  for (const s of schedules ?? []) {
    if (s.image_url) urls.push({ type: "schedule", legacy_id: s.legacy_id, url: s.image_url });
    if (s.home_image) urls.push({ type: "schedule_home", legacy_id: s.legacy_id, url: s.home_image });
  }
  for (const d of discography ?? []) {
    if (d.cover_image_url) urls.push({ type: "discography", legacy_id: d.legacy_id, url: d.cover_image_url });
  }
  return urls;
}

function analyzeSchedulesSource(schedulesRaw) {
  const homeImages = (schedulesRaw ?? [])
    .filter((s) => s.home_image)
    .map((s) => ({ legacy_id: s.id, url: s.home_image }));
  return { homeImages };
}

export function formatSupabaseSeedReport({
  dataDir,
  outDir,
  loaded,
  counts,
  nullStats,
  storageUrls,
  missingDates,
  outputs,
}) {
  const inputLines = Object.entries(loaded).map(([key, v]) => {
    const name = INPUT_FILES[key] ?? key;
    return `- \`${name}\`: ${v.present ? "loaded" : "**not generated**"} (${v.path})`;
  });

  return [
    "# Supabase Seed Report",
    "",
    "Generated by static-to-astro (Phase 3-E).",
    "",
    "> **Not connected to production Supabase.** No migrations in repo root `supabase/`.",
    "> `schema-draft.sql` is a draft — review before any database apply.",
    "",
    "## Metadata",
    "",
    `- **Data directory:** \`${dataDir}\``,
    `- **Output directory:** \`${outDir}\``,
    `- **Generated at:** ${new Date().toISOString()}`,
    "",
    "## Input files",
    "",
    ...inputLines,
    "",
    "## Output files",
    "",
    ...outputs.map((f) => `- \`${f}\``),
    "",
    "## Record counts",
    "",
    "| Table (seed file) | Rows |",
    "| --- | ---: |",
    `| schedules (\`seed-schedules.json\`) | ${counts.schedules} |`,
    `| schedule_months (\`seed-schedule-months.json\`) | ${counts.scheduleMonths} |`,
    `| discography (\`seed-discography.json\`) | ${counts.discography} |`,
    `| discography_tracks (\`seed-discography-tracks.json\`) | ${counts.discographyTracks} |`,
    "",
    "## Null / sparse fields (schedules)",
    "",
    "| Field | Null count |",
    "| --- | ---: |",
    ...Object.entries(nullStats.schedules).map(([k, n]) => `| ${k} | ${n} |`),
    "",
    missingDates.length
      ? `**Warning:** ${missingDates.length} schedule row(s) missing \`date\` — fix before DB insert (NOT NULL in schema).`
      : "_All schedule rows have date._",
    "",
    "## Null / sparse fields (discography)",
    "",
    "| Field | Null count |",
    "| --- | ---: |",
    ...Object.entries(nullStats.discography).map(([k, n]) => `| ${k} | ${n} |`),
    "",
    "## Storage migration required",
    "",
    `External image URLs in seed: **${storageUrls.length}** (Wix / static hosts).`,
    "",
    storageUrls.length
      ? storageUrls
          .slice(0, 20)
          .map((u) => `- ${u.type} \`${u.legacy_id}\`: ${u.url.slice(0, 80)}…`)
          .join("\n")
      : "_None_",
    storageUrls.length > 20 ? `\n_… and ${storageUrls.length - 20} more_` : "",
    "",
    "## Seed transformation rules",
    "",
    "### seed-schedules.json",
    "",
    "- `id` → `legacy_id`",
    "- `date` preserved (required for NOT NULL column)",
    "- `image` → `image_url`",
    "- `home_image` → `home_image_url` (home card thumbnail; null when not on home)",
    "- Preserves `show_on_home`, `home_order`, `published`",
    "",
    "### seed-schedule-months.json",
    "",
    "- Maps `month`, `label`, `route`, `count`; adds `sort_order` from file order",
    "",
    "### seed-discography.json",
    "",
    "- `id` → `legacy_id`; `cover_image` → `cover_image_url`",
    "- `tracks` omitted (see seed-discography-tracks.json)",
    "",
    "### seed-discography-tracks.json",
    "",
    "- One row per track; `discography_legacy_id` links to parent release",
    "",
    "## Manual review before production DB insert",
    "",
    "- [ ] Review `schema-draft.sql` with DBA / project owner",
    "- [ ] Resolve schedule rows without `date`",
    "- [ ] Upload images to Supabase Storage; replace URLs in seed (Phase 3-G dry-run / Phase 3-H upload)",
    "- [ ] Confirm `legacy_id` stability for upserts",
    "- [x] `home_image_url` column in schema draft (Phase 3-G)",
    "",
    "## Not in scope (Phase 3-E)",
    "",
    "- RLS policies",
    "- Auth / admin users",
    "- Live Supabase connection or `supabase db push`",
    "- Root `supabase/migrations/` changes",
    "",
    "## Phase 3-F suggestions",
    "",
    "- `insert-seed.mjs` using `@supabase/supabase-js` + service role (tooling-only env)",
    "- RLS: public read for `published = true`",
    "- Admin UI in `tools/static-to-astro/` for CRUD",
    "- Optional FK on `discography_tracks.discography_legacy_id`",
    "",
  ].join("\n");
}

export function writeSupabaseSeedOutputs({
  loaded,
  outDir,
  schedulesRaw,
}) {
  const outAbs = path.resolve(outDir);
  fs.mkdirSync(outAbs, { recursive: true });

  const outputs = [];

  fs.writeFileSync(path.join(outAbs, "schema-draft.sql"), SCHEMA_DRAFT_SQL, "utf8");
  outputs.push("schema-draft.sql");

  let seedSchedules = [];
  let seedMonths = [];
  let seedDiscography = [];
  let seedTracks = [];

  if (loaded.schedules.present) {
    seedSchedules = transformSchedulesForSupabase(loaded.schedules.data);
    fs.writeFileSync(
      path.join(outAbs, "seed-schedules.json"),
      `${JSON.stringify(seedSchedules, null, 2)}\n`,
      "utf8",
    );
    outputs.push("seed-schedules.json");
  }

  if (loaded.scheduleMonths.present) {
    seedMonths = transformScheduleMonthsForSupabase(loaded.scheduleMonths.data);
    fs.writeFileSync(
      path.join(outAbs, "seed-schedule-months.json"),
      `${JSON.stringify(seedMonths, null, 2)}\n`,
      "utf8",
    );
    outputs.push("seed-schedule-months.json");
  }

  if (loaded.discography.present) {
    seedDiscography = transformDiscographyForSupabase(loaded.discography.data);
    seedTracks = transformDiscographyTracksForSupabase(loaded.discography.data);
    fs.writeFileSync(
      path.join(outAbs, "seed-discography.json"),
      `${JSON.stringify(seedDiscography, null, 2)}\n`,
      "utf8",
    );
    fs.writeFileSync(
      path.join(outAbs, "seed-discography-tracks.json"),
      `${JSON.stringify(seedTracks, null, 2)}\n`,
      "utf8",
    );
    outputs.push("seed-discography.json", "seed-discography-tracks.json");
  }

  const missingDates = seedSchedules.filter((s) => !s.date).map((s) => s.legacy_id);

  const nullStats = {
    schedules: loaded.schedules.present
      ? countNulls(seedSchedules, [
          "title",
          "venue",
          "open_time",
          "start_time",
          "price",
          "description",
          "image_url",
          "home_image_url",
        ])
      : {},
    discography: loaded.discography.present
      ? countNulls(seedDiscography, ["artist", "label", "purchase_url", "streaming_url"])
      : {},
  };

  const storageUrls = [];
  if (loaded.schedules.present) {
    for (const s of seedSchedules) {
      if (s.image_url) storageUrls.push({ type: "schedule", legacy_id: s.legacy_id, url: s.image_url });
      if (s.home_image_url) {
        storageUrls.push({ type: "schedule_home", legacy_id: s.legacy_id, url: s.home_image_url });
      }
    }
  }
  if (loaded.discography.present) {
    for (const d of seedDiscography) {
      if (d.cover_image_url) {
        storageUrls.push({ type: "discography", legacy_id: d.legacy_id, url: d.cover_image_url });
      }
    }
  }

  return {
    outputs,
    counts: {
      schedules: seedSchedules.length,
      scheduleMonths: seedMonths.length,
      discography: seedDiscography.length,
      discographyTracks: seedTracks.length,
    },
    nullStats,
    storageUrls,
    missingDates,
    seedSchedules,
  };
}

export function appendSupabaseSeedToConversionReport(astroDir, summary) {
  const conversionPath = path.join(path.resolve(astroDir), "CONVERSION_REPORT.md");
  if (!fs.existsSync(conversionPath)) return;

  const block = [
    "",
    "## Supabase seed draft (Phase 3-E)",
    "",
    `- **Report:** \`${summary.reportRel}\``,
    `- **Output:** \`${summary.outRel}\``,
    `- **schema-draft.sql:** ${summary.hasSchema ? "yes" : "no"}`,
    `- **Seed JSON:** ${summary.seedFiles.join(", ")}`,
    `- **Row counts:** schedules ${summary.counts.schedules}, schedule_months ${summary.counts.scheduleMonths}, discography ${summary.counts.discography}, discography_tracks ${summary.counts.discographyTracks}`,
    `- **Production Supabase:** not connected (draft only)`,
    "",
    "### Phase 3-F (planned)",
    "",
    "- Insert script with service role (tooling env only)",
    "- RLS policies + Auth",
    "- Storage upload for image URLs",
    "",
  ].join("\n");

  let content = fs.readFileSync(conversionPath, "utf8");
  const marker = "## Supabase seed draft (Phase 3-E)";
  if (content.includes(marker)) {
    content = `${content.split(marker)[0].trimEnd()}${block}`;
  } else {
    content = `${content.trimEnd()}${block}`;
  }
  fs.writeFileSync(conversionPath, content, "utf8");
}

export function runSupabaseSeedPipeline({ dataDir, outDir, reportPath, astroDir }) {
  const { loaded } = loadSeedInputs(dataDir);
  const schedulesRaw = loaded.schedules.present ? loaded.schedules.data : [];

  const {
    outputs,
    counts,
    nullStats,
    storageUrls,
    missingDates,
  } = writeSupabaseSeedOutputs({
    loaded,
    outDir,
    schedulesRaw,
  });

  const outAbs = path.resolve(outDir);
  const dataAbs = path.resolve(dataDir);

  const reportContent = formatSupabaseSeedReport({
    dataDir: dataAbs,
    outDir: outAbs,
    loaded,
    counts,
    nullStats,
    storageUrls,
    missingDates,
    outputs: [...outputs, "SUPABASE_SEED_REPORT.md"],
  });

  const reportAbs = path.resolve(reportPath);
  fs.writeFileSync(reportAbs, reportContent, "utf8");

  if (astroDir) {
    const astroAbs = path.resolve(astroDir);
    appendSupabaseSeedToConversionReport(astroAbs, {
      reportRel: path.relative(astroAbs, reportAbs),
      outRel: path.relative(astroAbs, outAbs),
      hasSchema: outputs.includes("schema-draft.sql"),
      seedFiles: outputs.filter((f) => f.startsWith("seed-")),
      counts,
    });
  }

  return {
    loaded,
    counts,
    outputs,
    reportPath: reportAbs,
    outDir: outAbs,
    missingDates,
    storageUrls,
  };
}
